INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('heelevel3-c8735cdb-moex-00029', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-114-9b7ab1bb', 'sub-heelevel3-c8735cdb-02', NULL, 'single_choice', '未婚之甲女與乙男發生性關係後懷孕並產下丙。丙成年後找到乙，要求乙為認領。乙表示其生活 窮困，若丙願扶養，則乙願認領。下列敘述，何者正確？', '["認領後，如丙確有受扶養必要，乙有扶養能力，乙應扶養丙", "認領後，如乙確實無謀生能力但尚非無法維持生活，丙仍應扶養乙", "認領後，如乙確有受扶養必要，甲丙應共同扶養乙", "認領經雙方意思表示合致成立，乙所附條件為有效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:16+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00030', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-114-9b7ab1bb', 'sub-heelevel3-c8735cdb-02', NULL, 'single_choice', '甲乙為夫妻，生有A、B二子，並收養C為養女。乙於民國108年間死亡。今甲死亡，下列敘述， 何者正確？', '["A如對甲有重大之虐待或侮辱情事，經B及C共同表示A不得繼承；A則喪失其對甲之繼承權", "A及B於乙死亡後，否認C之繼承資格，並排除其對繼承財產之占有，C自知悉其得繼承之 時起2年間，得行使遺產酌給請求權", "B如有以詐欺或脅迫，使甲為關於繼承遺囑之情事，B則喪失其對甲之繼承權。但經甲宥恕者， 其繼承權不喪失", "甲如未立遺囑，C之應繼分為甲遺產之五分之一，A及B之應繼分各為甲遺產之五分之二"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:16+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00031', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-114-3082b5f1', 'sub-heelevel3-c8735cdb-03', NULL, 'essay', '甲之先人遺留 A洋樓經 T縣政府指定為縣定古蹟。T縣政府核定補助 A
洋樓修復再利用案後，擬與所有人甲締結「A洋樓修復再利用補助行政
契約」。雙方經多次協商後，就履約標的、補助金額、補助內容（含修復
計畫）、撥款方式、履約管理、違約責任、爭議處理等雙方權利義務重要
事項陸續達成共識，且均有往來書面文件及會議紀錄為憑。雙方關於撥
款之約定為第一期款於甲辦理工程招標後，撥付補助款 50%。甲遂於工
程招標後檢附工程契約向 T縣政府請求撥付補助金額新臺幣（以下同）
1 千萬元之 50%，即 500 萬元款項。T 縣政府拒絕，表示補助行政契約
尚未完成簽署，契約並未成立。T縣政府之主張是否有理由？假設 T縣
政府向該管高等行政法院起訴，請求「確認 A洋樓修復再利用補助行政
契約不存在」，其起訴是否合法？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:16+00:00", "source_pdf_sha1": "1959a582ef2c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0404", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00032', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-114-3082b5f1', 'sub-heelevel3-c8735cdb-03', NULL, 'essay', '甲所有之車輛，經民眾檢舉，於民國 114 年 1 月 15 日 19 時 40 分許，
行經 A市某路段時，有噪音妨礙安寧之虞，A市政府環境保護局（下稱
A 環保局）114 年 1 月 19 日以 B 函通知甲，限期於 114 年 1 月 27 日前
依 A環保局指定之時間、地點接受檢測，並完成檢測合格以免受罰。甲
於 114 年 1 月 25 日完成系爭車輛噪音檢測合格。惟仍對 B 函不服，於
114 年 2 月 2日提起訴願。試問訴願機關應如何為訴願決定？（25 分）
【參考法條】
噪音管制法
第 13 條：「人民得向主管機關檢舉使用中機動車輛噪音妨害安寧情形，
被檢舉之車輛經主管機關通知者，應於指定期限內至指定地點接受檢
驗；其檢舉辦法，由中央主管機關定之。」
第 28 條：「不依第 13 條規定檢驗，或經檢驗不符合管制標準者，處機動
車輛所有人或使用人新臺幣 1 千8 百元以上 3千6 百元以下罰鍰，並通
知限期改善；屆期仍未完成改善者，按次處罰。」
23550', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:16+00:00", "source_pdf_sha1": "1959a582ef2c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0404", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00033', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-114-3082b5f1', 'sub-heelevel3-c8735cdb-03', NULL, 'single_choice', '有關緊急命令之敘述，下列何者正確？', '["緊急命令之授權依據為一般法律", "緊急命令得暫時取代法律、變更法律", "緊急命令是由行政院院長發布", "緊急命令目的在於處理緊急危難或應付財經重大變故，故無須立法院之同意追認"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:16+00:00", "source_pdf_sha1": "1959a582ef2c", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00034', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-114-3082b5f1', 'sub-heelevel3-c8735cdb-03', NULL, 'single_choice', '依行政程序法規定，關於行政指導之敘述，下列何者正確？', '["行政指導無須以特定人為對象", "行政指導具有法律上之強制力", "相對人若明確拒絕指導時，行政機關應即停止行政指導，並不得據此對相對人為不利之處置", "針對非其職權或職掌之事務，行政機關仍得為行政指導"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:16+00:00", "source_pdf_sha1": "1959a582ef2c", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00035', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-114-3082b5f1', 'sub-heelevel3-c8735cdb-03', NULL, 'single_choice', '行政機關就不確定法律概念享有判斷餘地時，行政法院於下列何種情形應尊重行政機關之判斷？', '["事實如何涵攝於法律構成要件具有高度專業性，不能經由社會通念加以判斷", "判斷與評量以錯誤之事實為基礎", "決策過程未踐行應遵守之法律程序", "法律概念之解釋牴觸既存之上位規範"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:16+00:00", "source_pdf_sha1": "1959a582ef2c", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00036', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-114-3082b5f1', 'sub-heelevel3-c8735cdb-03', NULL, 'single_choice', '依現行法規定，關於委辦事項之敘述，下列何者錯誤？', '["委辦，乃地方自治團體在上級政府指揮監督下，執行上級政府交付辦理之事務", "上級政府應有法規依據，始得委辦事務予地方自治團體", "地方自治團體辦理委辦事務所為之行政處分，為委辦機關之行政處分", "地方自治團體訂定之委辦規則，應函報委辦機關核定後發布之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:16+00:00", "source_pdf_sha1": "1959a582ef2c", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00037', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-114-3082b5f1', 'sub-heelevel3-c8735cdb-03', NULL, 'single_choice', '關於行政法人之敘述，下列何者正確？', '["行政法人之任務限於完全不涉及公權力行使之事務", "不受其他機關指揮監督之國家通訊傳播委員會屬之", "行政法人所屬之職員須具有公務人員身分", "人民對於行政法人所為之行政處分得向其監督機關提起訴願"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:16+00:00", "source_pdf_sha1": "1959a582ef2c", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00038', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-114-3082b5f1', 'sub-heelevel3-c8735cdb-03', NULL, 'single_choice', '關於行政事件管轄權之敘述，下列何者錯誤？', '["行政事件如不能定土地管轄權，關於不動產事件，由不動產所在地行政機關管轄", "同一事件有數個行政機關有管轄權者，應由受理在先之機關管轄", "行政事件發生數行政機關管轄權爭議，應由其共同上級機關決定之", "行政事件發生數行政機關管轄權爭議，各該行政機關無共同上級機關，由各該行政機關協議定之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:16+00:00", "source_pdf_sha1": "1959a582ef2c", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL)
